import React, { useState } from 'react';
import Navbar from './components/Navbar';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard'; // Create this for your StatCards
import Patient from './pages/Patient';   // The file we just created
import './App.css';

function App() {
  // Logic to switch between pages (Mock Routing)
  const [activePage, setActivePage] = useState('dashboard');

  return (
    <div className="app-shell">
      {/* 1. Global Navbar stays at the top */}
      <Navbar />

      <div className="main-wrapper">
        {/* 2. Global Sidebar stays on the left */}
        {/* Pass the setter to Sidebar so clicking links changes the page */}
        <Sidebar activePage={activePage} setActivePage={setActivePage} />

        {/* 3. Dynamic Content Area */}
        <main className="content-area">
          {activePage === 'dashboard' ? (
            <Dashboard />
          ) : activePage === 'patients' ? (
            <Patient />
          ) : (
            <div className="coming-soon">
              <h2>{activePage.toUpperCase()} Module</h2>
              <p>This section is under development.</p>
            </div>
          )}
        </main>
      </div>
    </div>
  );
}

export default App;
